CustomFunction.Calculation:
// Returns JSONGetElement( json ; property ) where property is resolved from
// the field argument using this priority order:
//   1. GetFieldName( field ) — works when field is a real FM field reference;
//      strips the table occurrence prefix (everything before ::)
//   2. field contains :: — strips the table prefix from the string value
//   3. Fallback — assumes field is already the intended property name string
// Returns "?" if json does not pass JSON validation.
Let
(
[
_isValidJson = not Exact ( Left ( JSONFormatElements ( json ) ; 1 ) ; "?" ) ;
_fqName = GetFieldName ( field ) ;
_colonPos = Position ( field ; "::" ; 1 ; 1 ) ;
_property = Case (
	not IsEmpty ( _fqName ) and Position ( _fqName ; "::" ; 1 ; 1 ) > 0 ;
		Middle ( _fqName ; Position ( _fqName ; "::" ; 1 ; 1 ) + 2 ; Length ( _fqName ) ) ;
	not IsEmpty ( _fqName ) ;
		_fqName ;
	_colonPos > 0 ;
		Middle ( field ; _colonPos + 2 ; Length ( field ) ) ;
	// ELSE
	field
	)
];
Case (
	not _isValidJson ;
		"?" ;
	// ELSE
	JSONGetElement ( json ; _property )
	)
)
